#!/usr/bin/env python3
from pathlib import Path
R=Path(__file__).resolve().parents[1]; O=R/'assets'; O.mkdir(exist_ok=True)
def svg(dark=False):
 bg='#101114' if dark else '#1548ff'; ink='#f4f0e8'; acid='#c9ff35'; orange='#ff6f3d'; lav='#f3c6ff'
 return f'''<svg xmlns="http://www.w3.org/2000/svg" width="1280" height="560" viewBox="0 0 1280 560" role="img" aria-labelledby="t d"><title id="t">Kartik Hulmukh — Software that shows its work</title><desc id="d">Three connected mechanisms represent confirmation, source review, and behavioral testing.</desc><rect width="1280" height="560" fill="{bg}"/><style>.big{{font:900 88px Arial,sans-serif;letter-spacing:-5px}}.small{{font:700 12px Arial,sans-serif;letter-spacing:2px}}.label{{font:800 16px Arial,sans-serif}}</style><text x="58" y="58" class="small" fill="{acid}">KARTIK HULMUKH / SYSTEMS IN MOTION / 2026</text><text x="58" y="160" class="big" fill="{ink}">SOFTWARE THAT</text><text x="58" y="248" class="big" fill="{acid}">SHOWS ITS WORK.</text><g transform="translate(60 325)"><rect width="330" height="150" rx="75" fill="none" stroke="{acid}" stroke-width="3"/><circle cx="75" cy="75" r="42" fill="{acid}"/><text x="140" y="68" class="small" fill="{ink}">01 / KAIRO-PHANTOM</text><text x="140" y="94" class="label" fill="{ink}">ACTION → RECEIPT</text></g><g transform="translate(470 325)"><path d="M0 75h70l45-55 60 110 55-70h100" fill="none" stroke="{orange}" stroke-width="7"/><text x="0" y="22" class="small" fill="{ink}">02 / PROJECT X-RAY</text><text x="0" y="146" class="label" fill="{ink}">SOURCE → REVIEW</text></g><g transform="translate(880 325)"><rect width="140" height="105" fill="{lav}"/><rect x="170" width="140" height="105" fill="none" stroke="{lav}" stroke-width="3"/><path d="M140 52h30" stroke="{acid}" stroke-width="5"/><text x="0" y="146" class="label" fill="{ink}">03 / BASE ↔ HEAD</text></g><text x="1000" y="60" class="small" fill="{ink}">LOCAL-FIRST</text><text x="1000" y="84" class="small" fill="{ink}">HUMAN-GATED</text><text x="1000" y="108" class="small" fill="{ink}">INSPECTABLE</text><text x="58" y="525" class="small" fill="{ink}">OPERATE THE PROJECT MECHANISMS → kartik24hulmukh.github.io/Kartik24Hulmukh/</text></svg>'''
for d in (False,True):(O/f'hero-{"dark" if d else "light"}.svg').write_text(svg(d),encoding='utf-8')
print('Rendered hero assets.')
